def main():
    input = sys.stdin.buffer.readline
    N, K = map(int, input().split())
    total = N * K

    adj = [[] for _ in range(total)]
    for _ in range(total - 1):
        u, v = map(int, input().split())
        u -= 1
        v -= 1
        adj[u].append(v)
        adj[v].append(u)

    parent = [-2] * total
    parent[0] = -1
    order = []
    stack = [0]

    while stack:
        v = stack.pop()
        order.append(v)
        for to in adj[v]:
            if to == parent[v]:
                continue
            parent[to] = v
            stack.append(to)

    dp = [0] * total
    ok = True

    for v in reversed(order):
        vals = []
        for to in adj[v]:
            if parent[to] == v and dp[to] > 0:
                vals.append(dp[to])

        if len(vals) >= 3:
            ok = False
            break

        if len(vals) == 0:
            dp[v] = 0 if K == 1 else 1

        elif len(vals) == 1:
            x = vals[0] + 1
            if x == K:
                dp[v] = 0
            elif x < K:
                dp[v] = x
            else:
                ok = False
                break

        else:
            if vals[0] + vals[1] + 1 == K:
                dp[v] = 0
            else:
                ok = False
                break

    if ok and dp[0] == 0:
        print("Yes")
    else:
        print("No")

