def solve():
    import sys
    from collections import defaultdict
    data = sys.stdin.read().split()
    N = int(data[0]); M = int(data[1]); S = data[2]
    MOD = 998244353

    # distinct chars in S and their multiplicity among 26 letters
    charset = set(S)
    # transitions: for each character type, precompute
    # We'll enumerate: characters in charset (each count 1), other chars (count 26 - len(charset))

    def transition(row, c):
        new = [0]*(N+1)
        for i in range(1, N+1):
            if S[i-1] == c:
                new[i] = max(new[i-1], row[i], row[i-1]+1)
            else:
                new[i] = max(new[i-1], row[i])
        return tuple(new)

    # cache transitions
    trans_cache = {}

    def get_trans(row):
        if row in trans_cache:
            return trans_cache[row]
        # list of (newrow, weight)
        res = defaultdict(int)
        for c in charset:
            nr = transition(row, c)
            res[nr] += 1
        other_count = 26 - len(charset)
        if other_count > 0:
            # pick any char not in S; if all 26 in S, no other
            # find a char not in charset
            for cc in 'abcdefghijklmnopqrstuvwxyz':
                if cc not in charset:
                    nr = transition(row, cc)
                    res[nr] += other_count
                    break
        result = list(res.items())
        trans_cache[row] = result
        return result

    start = tuple([0]*(N+1))
    dp = {start: 1}

    for _ in range(M):
        ndp = defaultdict(int)
        for row, cnt in dp.items():
            for nr, w in get_trans(row):
                ndp[nr] = (ndp[nr] + cnt * w) % MOD
        dp = ndp

    ans = [0]*(N+1)
    for row, cnt in dp.items():
        k = row[N]
        ans[k] = (ans[k] + cnt) % MOD

    print(' '.join(map(str, ans)))

solve()
