from bisect import bisect_left

def main():
    input = sys.stdin.buffer.readline
    N, X = map(int, input().split())

    dp = [[0] * (X + 1) for _ in range(3)]

    for _ in range(N):
        v, a, c = map(int, input().split())
        d = dp[v - 1]
        for cal in range(X, c - 1, -1):
            val = d[cal - c] + a
            if val > d[cal]:
                d[cal] = val

    ok = 0
    ng = min(dp[0][X], dp[1][X], dp[2][X]) + 1

    while ng - ok > 1:
        mid = (ok + ng) // 2
        need = 0
        for i in range(3):
            need += bisect_left(dp[i], mid)
        if need <= X:
            ok = mid
        else:
            ng = mid

    print(ok)

if __name__ == "__main__":
    main()
