import sys

def count_snake_leq(n: int) -> int:
    if n < 10:
        return 0

    digits = list(map(int, str(n)))
    length = len(digits)
    ans = 0

    for l in range(2, length):
        for first in range(1, 10):
            ans += first ** (l - 1)

    first_digit = digits[0]

    for first in range(1, first_digit):
        ans += first ** (length - 1)

    for i in range(1, length):
        cur = digits[i]
        remaining = length - i - 1

        ans += min(cur, first_digit) * (first_digit ** remaining)

        if cur >= first_digit:
            break
    else:
        ans += 1

    return ans

def main():
    L, R = map(int, sys.stdin.read().split())
    print(count_snake_leq(R) - count_snake_leq(L - 1))

if __name__ == "__main__":
    main()
